#include <stdio.h>
#include <string.h>
#include <ctype.h>

void formatName(char *line){
    char *parts[3];
    int cnt=0;
    char *tok=strtok(line," \n\r");
    while(tok && cnt<3){
        parts[cnt++]=tok;
        tok=strtok(NULL," \n\r");
    }
    for(int i=0;i<cnt-1;i++){
        putchar(toupper(parts[i][0]));
        putchar('.');
        putchar(' ');
    }
    // last part
    char *last=parts[cnt-1];
    putchar(toupper(last[0]));
    for(int i=1;last[i];i++) putchar(tolower(last[i]));
    putchar('\n');
}

int main(){
    int T; if(scanf("%d",&T)!=1) return 0; 
    getchar(); // consume newline after T
    char line[256];
    for(int t=0;t<T;t++){
        if(!fgets(line,sizeof(line),stdin)) break;
        // remove trailing newline if present
        size_t len=strlen(line);
        if(len && (line[len-1]=='\n' || line[len-1]=='\r')) line[len-1]='\0';
        formatName(line);
    }
    return 0;
}

