#include <bits/stdc++.h>
using namespace std;

string capitalize(const string &s){
    string res=s;
    if(!res.empty()) res[0]=toupper(res[0]);
    for(size_t i=1;i<res.size();++i) res[i]=tolower(res[i]);
    return res;
}

int main(){
    ios::sync_with_stdio(false);
    cin.tie(nullptr);
    int T; if(!(cin>>T)) return 0; string dummy; getline(cin,dummy); // consume endline
    for(int tc=0; tc<T; ++tc){
        string line; getline(cin,line);
        stringstream ss(line);
        vector<string> parts; string w; while(ss>>w) parts.push_back(w);
        for(size_t i=0;i+1<parts.size();++i){
            cout<<char(toupper(parts[i][0]))<<". ";
        }
        cout<<capitalize(parts.back());
        if(tc+1<T) cout<<'\n';
    }
    return 0;
}

