import java.io.*;
import java.util.*;

public class Main {
    private static String capitalize(String s){
        if(s.isEmpty()) return s;
        StringBuilder sb=new StringBuilder(s.length());
        sb.append(Character.toUpperCase(s.charAt(0)));
        for(int i=1;i<s.length();i++) sb.append(Character.toLowerCase(s.charAt(i)));
        return sb.toString();
    }
    public static void main(String[] args) throws Exception {
        BufferedReader br=new BufferedReader(new InputStreamReader(System.in));
        int T=Integer.parseInt(br.readLine().trim());
        StringBuilder out=new StringBuilder();
        for(int t=0;t<T;t++){
            String line=br.readLine();
            while(line!=null && line.isEmpty()) line=br.readLine(); // skip empty lines
            String[] parts=line.trim().split("\\s+");
            for(int i=0;i<parts.length-1;i++){
                out.append(Character.toUpperCase(parts[i].charAt(0))).append('.').append(' ');
            }
            out.append(capitalize(parts[parts.length-1]));
            if(t+1<T) out.append('\n');
        }
        System.out.print(out.toString());
    }
}

